let state = null;

export function init(element, dotNetRef, timeoutMs) {
    const events = ["mousemove", "keydown", "click", "scroll"];
    let timerId = null;
    let isIdle = false;

    function resetTimer() {
        if (timerId !== null) {
            clearTimeout(timerId);
        }

        if (isIdle) {
            isIdle = false;
            dotNetRef.invokeMethodAsync("NotifyActive");
        }

        timerId = setTimeout(() => {
            isIdle = true;
            dotNetRef.invokeMethodAsync("NotifyIdle");
        }, timeoutMs);
    }

    events.forEach(evt => element.addEventListener(evt, resetTimer, { passive: true }));

    // Also listen on the document for events that may not bubble to the wrapper
    events.forEach(evt => document.addEventListener(evt, resetTimer, { passive: true }));

    // Start the initial timer
    resetTimer();

    state = { element, events, timerId: () => timerId, resetTimer };
}

export function dispose() {
    if (!state) return;

    const { element, events, timerId, resetTimer } = state;

    clearTimeout(timerId());
    events.forEach(evt => element.removeEventListener(evt, resetTimer));
    events.forEach(evt => document.removeEventListener(evt, resetTimer));

    state = null;
}

